SourceCode.Declaration:
/// <summary>
/// The OHMSSalesWFTypeEventHandler workflow event handler.
/// Responds to type-level workflow events (started, canceled, completed) and
/// stamps the matching status onto the originating SalesTable record.
/// </summary>
public class OHMSSalesWFTypeEventHandler implements WorkflowCanceledEventHandler,
    WorkflowCompletedEventHandler,
    WorkflowStartedEventHandler
{
}

Method.Source:
/// <summary>Fires when the workflow starts. Marks the order as Started.</summary>
/// <param name = "_workflowEventArgs">Event args; supplies the record RecId.</param>
public void started(WorkflowEventArgs _workflowEventArgs)
{
    OHMSSalesWFStatusHelper::updateWorkflowStatus(
        _workflowEventArgs.parmWorkflowContext().parmRecId(),
        OHMSSalesWFStatus::Started);
}

/// <summary>Fires when the workflow is canceled. Marks the order as Cancelled.</summary>
/// <param name = "_workflowEventArgs">Event args; supplies the record RecId.</param>
public void canceled(WorkflowEventArgs _workflowEventArgs)
{
    OHMSSalesWFStatusHelper::updateWorkflowStatus(
        _workflowEventArgs.parmWorkflowContext().parmRecId(),
        OHMSSalesWFStatus::Cancelled);
}

/// <summary>Fires when the workflow completes. Marks the order as Complete.</summary>
/// <param name = "_workflowEventArgs">Event args; supplies the record RecId.</param>
public void completed(WorkflowEventArgs _workflowEventArgs)
{
    OHMSSalesWFStatusHelper::updateWorkflowStatus(
        _workflowEventArgs.parmWorkflowContext().parmRecId(),
        OHMSSalesWFStatus::Complete);
}
